const transformedDirections: Record<ProbeQuality, number[]> = {
  [ProbeQuality.q12]: new Array(sourceDirections[ProbeQuality.q12].length),
  [ProbeQuality.q42]: new Array(sourceDirections[ProbeQuality.q42].length),
  [ProbeQuality.q92]: new Array(sourceDirections[ProbeQuality.q92].length),
}

const _q = { x: 0, y: 0, z: 0, w: 1 }
const _m = new Array(9)
const _v = new Vector3()

function randomQuaternion(rand: () => number) {
  const u1 = rand()
  const u2 = rand()
  const u3 = rand()

  const sqrt1MinusU1 = Math.sqrt(1 - u1)
  const sqrtU1 = Math.sqrt(u1)

  const theta1 = 2 * Math.PI * u2
  const theta2 = 2 * Math.PI * u3

  _q.x = sqrt1MinusU1 * Math.sin(theta1)
  _q.y = sqrt1MinusU1 * Math.cos(theta1)
  _q.z = sqrtU1 * Math.sin(theta2)
  _q.w = sqrtU1 * Math.cos(theta2)
}

function quatToMatrix3() {
  const { x, y, z, w } = _q

  const xx = x * x, yy = y * y, zz = z * z
  const xy = x * y, xz = x * z, yz = y * z
  const wx = w * x, wy = w * y, wz = w * z

  _m[0] = 1 - 2 * (yy + zz)
  _m[1] = 2 * (xy - wz)
  _m[2] = 2 * (xz + wy)

  _m[3] = 2 * (xy + wz)
  _m[4] = 1 - 2 * (xx + zz)
  _m[5] = 2 * (yz - wx)

  _m[6] = 2 * (xz - wy)
  _m[7] = 2 * (yz + wx)
  _m[8] = 1 - 2 * (xx + yy)
}

function applyRotation() {
  const { x, y, z } = _v
  _v.x = _m[0] * x + _m[1] * y + _m[2] * z
  _v.y = _m[3] * x + _m[4] * y + _m[5] * z
  _v.z = _m[6] * x + _m[7] * y + _m[8] * z
}

function transformDirections(directions: number[], transformed: number[]) {
  for (let i = 0; i < directions.length; i += 3) {
    _v.set(directions[i], directions[i + 1], directions[i + 2])
    applyRotation()
    transformed[i] = _v.x
    transformed[i + 1] = _v.y
    transformed[i + 2] = _v.z
  }
}

class ClosestIntersectionResult {
  distance = Infinity
  point = new Vector3()
  normal = new Vector3()
  object: Object3D | null = null
}

function _getClosestIntersection(
  root: Object3D,
  quality: ProbeQuality,
  origin: Vector3,
  maxDistance: number,
  randomTryCount: number,
  rand: () => number,
): ClosestIntersectionResult {
  const source = sourceDirections[quality]
  const transformed = transformedDirections[quality]
  const directionCount = source.length / 3

  const result = new ClosestIntersectionResult()

  const probeSphere = new Sphere(origin, maxDistance)
  const geometryProxySphere = new Sphere(new Vector3(), 0)

  const queue = [root]
  const meshes = [] as Mesh[]
  while (queue.length > 0) {
    const obj = queue.pop()!
    queue.push(...obj.children)
    if (obj instanceof Mesh) {
      meshes.push(obj)
      obj.geometry.computeBoundingSphere()
    }
  }

  for (let tryIndex = 0; tryIndex < randomTryCount; tryIndex++) {
    randomQuaternion(rand)
    quatToMatrix3()
    transformDirections(source, transformed)

    for (const mesh of meshes) {
      const geometry = mesh.geometry
      const instanceMatrix = (mesh as InstancedMesh).instanceMatrix as InstancedBufferAttribute | undefined

      if (instanceMatrix) {
        console.warn('Instanced meshes are not supported by getClosestIntersection yet.')
        continue
      }

      else {
        geometryProxySphere.copy(geometry.boundingSphere!).applyMatrix4(mesh.matrixWorld)
        if (!probeSphere.intersectsSphere(geometryProxySphere)) {
          continue
        }
        for (let i = 0; i < directionCount; i++) {
          _v.set(transformed[i * 3], transformed[i * 3 + 1], transformed[i * 3 + 2])
          const ray = { origin, direction: _v }
        }
      }
    }
  }

  return result
}

const defaultOptions = {
  /**
   * The point from which to cast rays.
   * 
   * Defaults to the world origin (0, 0, 0).
   */
  origin: <Vector3Declaration>0,

  /**
   * The maximum distance to check for intersections. 
   * 
   * Defaults to Infinity.
   */
  maxDistance: Infinity,

  /**
   * Quality of the probe, which determines the number of rays cast in different directions.
   */
  quality: ProbeQuality.q42,

  /**
   * Number of random tries to perform in addition to the fixed directions. Each 
   * try will generate a random direction and cast a ray in that direction.
   */
  randomTryCount: 1,

  /**
   * The random number generator function to use for generating random directions.
   * 
   * Defaults to Math.random.
   */
  rand: Math.random,
}

export function getClosestIntersection(
  root: Object3D,
  options?: Partial<typeof defaultOptions>,
): ClosestIntersectionResult {
  const {
    origin,
    maxDistance,
    quality,
    randomTryCount,
    rand,
  } = { ...defaultOptions, ...options }
  return _getClosestIntersection(
    root,
    quality,
    fromVector3Declaration(origin),
    maxDistance,
    randomTryCount,
    rand,
  )
}